private boolean testAttr(Attr attr) {
    String nodePrefix = DOMNodePointer.getPrefix(attr);
    String nodeLocalName = DOMNodePointer.getLocalName(attr);

    if (nodePrefix != null && nodePrefix.equals("xmlns")) {
        return false;
    }

    if (nodePrefix == null && nodeLocalName.equals("xmlns")) {
        return false;
    }

    String testLocalName = name.getName();
    if ("*".equals(testLocalName) || (testLocalName.equals(nodeLocalName) && (name.getPrefix() == null || "*".equals(name.getPrefix())))) {
        if (name.getPrefix() == null || "*".equals(name.getPrefix()) || equalStrings(name.getPrefix(), nodePrefix)) {
            return true;
        }
        String testNS = null;
        if (name.getPrefix() != null && !"*".equals(name.getPrefix())) {
            testNS = parent.getNamespaceURI(name.getPrefix());
        }
        String nodeNS = null;
        if (nodePrefix != null) {
            nodeNS = parent.getNamespaceURI(nodePrefix);
        }
        return equalStrings(testNS, nodeNS);
    }
    return false;
}

